#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct BootPhase(pub u8);

#[derive(Debug, Clone)]
pub struct BootLogEntry {
    pub phase: BootPhase,
    pub message: String,
}

#[allow(dead_code)]
pub struct Runtime {
    master_key_set: bool,
    boot_log: Vec<BootLogEntry>,
    service_pids: std::collections::HashMap<String, Pid>,
}

impl std::fmt::Debug for Runtime {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("Runtime")
            .field("master_key_set", &self.master_key_set)
            .finish()
    }
}

impl Runtime {
    pub async fn bootstrap_with_root(root: &Path) -> Result<Self, AvixError> {
        let mut log = Vec::new();
        let mut service_pids = std::collections::HashMap::new();

        // Phase 0: init
        log.push(BootLogEntry {
            phase: BootPhase(0),
            message: "phase 0: init".into(),
        });

        // Phase 1: check auth.conf
        let auth_conf = root.join("etc/auth.conf");
        if !auth_conf.exists() {
            return Err(AvixError::ConfigParse(
                "auth.conf not found — run `avix config init` first".into(),
            ));
        }
        log.push(BootLogEntry {
            phase: BootPhase(1),
            message: "phase 1: VFS mount".into(),
        });

        // Phase 2: load master key from env and zero it
        let master_key = std::env::var("AVIX_MASTER_KEY")
            .map_err(|_| AvixError::ConfigParse("AVIX_MASTER_KEY env var not set".into()))?;
        // Zero the env var immediately
        std::env::remove_var("AVIX_MASTER_KEY");
        let _key_bytes = master_key.into_bytes(); // held in memory only
        log.push(BootLogEntry {
            phase: BootPhase(2),
            message: "phase 2: config + master key".into(),
        });

        // Phase 3: start built-in services
        let builtins = ["logger", "memfs", "auth", "router"];
        for (i, svc) in builtins.iter().enumerate() {
            service_pids.insert(svc.to_string(), Pid::new((i + 1) as u32));
        }
        log.push(BootLogEntry {
            phase: BootPhase(3),
            message: "phase 3: services started".into(),
        });

        Ok(Runtime {
            master_key_set: true,
            boot_log: log,
            service_pids,
        })
    }

    pub fn has_master_key(&self) -> bool {
        self.master_key_set
    }

    pub fn boot_log(&self) -> &[BootLogEntry] {
        &self.boot_log
    }

    pub async fn service_pid(&self, name: &str) -> Option<Pid> {
        self.service_pids.get(name).copied()
    }
}

use crate::error::AvixError;
use std::path::PathBuf;

pub struct ConfigInitParams {
    pub root: PathBuf,
    pub identity_name: String,
    pub credential_type: String,
    pub role: String,
    pub master_key_source: String,
    pub mode: String,
}

pub struct ConfigInitResult {
    pub api_key: String,
}

pub fn run_config_init(params: ConfigInitParams) -> Result<ConfigInitResult, AvixError> {
    let etc_dir = params.root.join("etc");

    // Idempotent: if auth.conf exists, return ok
    if etc_dir.join("auth.conf").exists() {
        return Ok(ConfigInitResult {
            api_key: "sk-avix-existing".into(),
        });
    }

    std::fs::create_dir_all(&etc_dir).map_err(|e| AvixError::ConfigParse(e.to_string()))?;

    let raw_key = format!("sk-avix-{}", uuid::Uuid::new_v4());

    use hmac::{Hmac, Mac};
    use sha2::Sha256;
    type HmacSha256 = Hmac<Sha256>;
    let mut mac =
        HmacSha256::new_from_slice(b"config-init-secret").expect("HMAC accepts any key size");
    mac.update(raw_key.as_bytes());
    let key_hash = format!("hmac-sha256:{}", hex::encode(mac.finalize().into_bytes()));

    let auth_conf = format!(
        r#"apiVersion: avix/v1
kind: AuthConfig
policy:
  session_ttl: 8h
  require_tls: false
identities:
  - name: {name}
    uid: 1001
    role: {role}
    credential:
      type: api_key
      key_hash: "{key_hash}"
"#,
        name = params.identity_name,
        role = params.role,
        key_hash = key_hash,
    );

    std::fs::write(etc_dir.join("auth.conf"), auth_conf)
        .map_err(|e| AvixError::ConfigParse(e.to_string()))?;

    Ok(ConfigInitResult { api_key: raw_key })
}

use std::collections::HashMap;
use std::sync::RwLock;

#[derive(Debug, Clone)]
pub struct ProviderStatus {
    pub name: String,
    pub enabled: bool,
    pub modalities: Vec<String>,
    pub is_healthy: bool,
}

#[derive(Debug, Clone)]
pub struct TokenUsage {
    pub provider: String,
    pub input_tokens: u64,
    pub output_tokens: u64,
}

impl TokenUsage {
    pub fn total(&self) -> u64 {
        self.input_tokens + self.output_tokens
    }
}

pub struct LlmCliHandler {
    /// Provider name -> enabled flag
    providers: RwLock<HashMap<String, bool>>,
    /// Default provider per modality
    defaults: RwLock<HashMap<String, String>>,
    /// Provider -> supported modalities (for validation)
    modalities: HashMap<String, Vec<String>>,
    /// Token usage counters
    usage: RwLock<HashMap<String, TokenUsage>>,
}

impl LlmCliHandler {
    pub fn new(
        provider_names: Vec<String>,
        provider_modalities: HashMap<String, Vec<String>>,
    ) -> Self {
        let providers: HashMap<String, bool> =
            provider_names.iter().map(|n| (n.clone(), true)).collect();
        let usage: HashMap<String, TokenUsage> = provider_names
            .iter()
            .map(|n| {
                (
                    n.clone(),
                    TokenUsage {
                        provider: n.clone(),
                        input_tokens: 0,
                        output_tokens: 0,
                    },
                )
            })
            .collect();
        Self {
            providers: RwLock::new(providers),
            defaults: RwLock::new(HashMap::new()),
            modalities: provider_modalities,
            usage: RwLock::new(usage),
        }
    }

    pub fn status(&self) -> Vec<ProviderStatus> {
        let providers = self.providers.read().unwrap();
        providers
            .iter()
            .map(|(name, &enabled)| ProviderStatus {
                name: name.clone(),
                enabled,
                modalities: self.modalities.get(name).cloned().unwrap_or_default(),
                is_healthy: enabled, // simplified
            })
            .collect()
    }

    pub fn models(&self, modality_filter: Option<&str>) -> HashMap<String, Vec<String>> {
        let providers = self.providers.read().unwrap();
        let mut result: HashMap<String, Vec<String>> = HashMap::new();
        for (name, &enabled) in providers.iter() {
            if !enabled {
                continue;
            }
            let mods = self.modalities.get(name).cloned().unwrap_or_default();
            for m in &mods {
                if modality_filter.is_none_or(|f| f == m) {
                    result.entry(m.clone()).or_default().push(name.clone());
                }
            }
        }
        result
    }

    pub fn usage(&self) -> Vec<TokenUsage> {
        self.usage.read().unwrap().values().cloned().collect()
    }

    pub fn disable_provider(&self, name: &str) -> Result<(), String> {
        let mut providers = self.providers.write().unwrap();
        if providers.contains_key(name) {
            providers.insert(name.to_string(), false);
            Ok(())
        } else {
            Err(format!("unknown provider: {name}"))
        }
    }

    pub fn enable_provider(&self, name: &str) -> Result<(), String> {
        let mut providers = self.providers.write().unwrap();
        if providers.contains_key(name) {
            providers.insert(name.to_string(), true);
            Ok(())
        } else {
            Err(format!("unknown provider: {name}"))
        }
    }

    pub fn set_default(&self, modality: &str, provider: &str) -> Result<(), String> {
        // Validate that provider supports this modality
        let supported = self
            .modalities
            .get(provider)
            .map(|m| m.contains(&modality.to_string()))
            .unwrap_or(false);
        if !supported {
            return Err(format!(
                "provider {provider} does not support modality {modality}"
            ));
        }
        self.defaults
            .write()
            .unwrap()
            .insert(modality.to_string(), provider.to_string());
        Ok(())
    }

    pub fn get_default(&self, modality: &str) -> Option<String> {
        self.defaults.read().unwrap().get(modality).cloned()
    }

    pub fn rotate_key(&self, _provider: &str) -> Result<(), String> {
        // Placeholder — in production would update the credential
        Ok(())
    }
}

