#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum CredentialType {
    ApiKey {
        key_hash: String,
        #[serde(default)]
        header: Option<String>,
    },
    Password {
        password_hash: String,
    },
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AuthIdentity {
    pub name: String,
