use crate::llm_client::{LlmCompleteResponse, StopReason};
use crate::llm_svc::adapter::AvixToolCall;
use crate::types::tool::ToolName;

pub enum TurnAction {
    ReturnResult(String),
    DispatchTools(Vec<AvixToolCall>),
    SummariseContext,
}

pub fn interpret_stop_reason(resp: &LlmCompleteResponse) -> TurnAction {
    match resp.stop_reason {
        StopReason::EndTurn | StopReason::StopSequence => {
            let text = resp
                .content
                .iter()
                .filter_map(|c| c["text"].as_str())
                .collect::<Vec<_>>()
                .join("");
            TurnAction::ReturnResult(text)
        }
        StopReason::ToolUse => {
            let calls = resp
                .content
                .iter()
                .filter(|c| c["type"] == "tool_use")
                .map(|c| {
                    let mangled = c["name"].as_str().unwrap_or("");
                    let name = ToolName::unmangle(mangled)
                        .map(|n| n.as_str().to_string())
                        .unwrap_or_else(|_| mangled.replace("__", "/"));
                    AvixToolCall {
                        call_id: c["id"].as_str().unwrap_or("").to_string(),
                        name,
                        args: c["input"].clone(),
                    }
                })
                .collect();
            TurnAction::DispatchTools(calls)
        }
        StopReason::MaxTokens => TurnAction::SummariseContext,
    }
}

use crate::types::capability_map::CapabilityToolMap;
use crate::types::{token::CapabilityToken, tool::ToolVisibility};
use std::collections::HashSet;

pub fn compute_cat2_tools(token: &CapabilityToken) -> Vec<(String, ToolVisibility)> {
    let map = CapabilityToolMap::default();
    let mut tools = Vec::new();

    // Always-present tools
    for &name in map.always_present() {
        tools.push((name.to_string(), ToolVisibility::All));
    }

    // Capability-gated tools
    for cap in &token.granted_tools {
        for &name in map.tools_for_capability(cap) {
            tools.push((name.to_string(), ToolVisibility::All));
        }
    }

    // Deduplicate
    let mut seen = HashSet::new();
    tools.retain(|(name, _)| seen.insert(name.clone()));
    tools
}

