use std::collections::HashMap;
use std::sync::Arc;
use std::time::Duration;
use tokio::sync::Mutex;
use tokio::task::JoinHandle;

#[derive(Default)]
pub struct RefreshScheduler {
    handles: Arc<Mutex<HashMap<String, JoinHandle<()>>>>,
}

impl RefreshScheduler {
    pub fn new() -> Self {
        Self::default()
    }

    pub async fn schedule<F>(&self, name: &str, interval: Duration, callback: F)
    where
        F: Fn() + Send + 'static,
    {
        let handle = tokio::spawn(async move {
            let mut ticker = tokio::time::interval(interval);
            ticker.tick().await; // skip first immediate tick
            ticker.tick().await; // wait for first real tick
            callback();
        });
        self.handles.lock().await.insert(name.to_string(), handle);
    }
}

use crate::config::{LlmConfig, ProviderConfig};
use crate::error::AvixError;
use crate::types::Modality;
use std::collections::HashMap;

pub struct RoutingEngine {
    defaults: HashMap<String, String>,
    providers: HashMap<String, ProviderConfig>,
}

impl RoutingEngine {
    pub fn from_config(config: &LlmConfig) -> Self {
        let mut defaults = HashMap::new();
        defaults.insert("text".into(), config.spec.default_providers.text.clone());
        defaults.insert("image".into(), config.spec.default_providers.image.clone());
        defaults.insert(
            "speech".into(),
            config.spec.default_providers.speech.clone(),
        );
        defaults.insert(
            "transcription".into(),
            config.spec.default_providers.transcription.clone(),
        );
        defaults.insert(
            "embedding".into(),
            config.spec.default_providers.embedding.clone(),
        );

        let providers = config
            .spec
            .providers
            .iter()
            .map(|p| (p.name.clone(), p.clone()))
            .collect();

        Self {
            defaults,
            providers,
        }
    }

    pub fn resolve(
        &self,
        modality: Modality,
        explicit: Option<&str>,
    ) -> Result<&ProviderConfig, AvixError> {
        let name = if let Some(explicit_name) = explicit {
            explicit_name.to_string()
        } else {
            self.defaults
                .get(modality.as_str())
                .cloned()
                .ok_or_else(|| {
                    AvixError::ConfigParse(format!("no default provider for {}", modality.as_str()))
                })?
        };

        let provider = self
            .providers
            .get(&name)
            .ok_or_else(|| AvixError::ConfigParse(format!("provider not found: {name}")))?;

        if !provider.modalities.contains(&modality) {
            return Err(AvixError::ConfigParse(format!(
                "provider '{}' does not support modality '{}'",
                name,
                modality.as_str()
            )));
        }

        Ok(provider)
    }
}

use crate::error::AvixError;
use crate::types::tool::ToolName;

#[derive(Debug, Clone)]
pub struct McpToolDescriptor {
    pub name: String,
    pub description: String,
    pub server: String,
}

pub struct McpBridge {
    server_name: String,
    tools: Vec<McpToolDescriptor>,
}

impl McpBridge {
    pub fn new(server_name: impl Into<String>) -> Self {
        Self {
            server_name: server_name.into(),
            tools: Vec::new(),
        }
    }

    /// Register a raw MCP tool name (e.g. "create-issue") with prefix
    pub fn register_tool(
        &mut self,
        raw_name: &str,
        description: &str,
    ) -> Result<McpToolDescriptor, AvixError> {
        let namespaced = format!("mcp/{}/{}", self.server_name, raw_name);
        // Validate the name
        ToolName::parse(&namespaced)?;
        let desc = McpToolDescriptor {
            name: namespaced,
            description: description.to_string(),
            server: self.server_name.clone(),
        };
        self.tools.push(desc.clone());
        Ok(desc)
    }

    pub fn tools(&self) -> &[McpToolDescriptor] {
        &self.tools
    }

    pub fn tool_count(&self) -> usize {
        self.tools.len()
    }

    /// Strip the mcp/<server>/ prefix to get the raw outbound tool name
    pub fn outbound_name(tool_name: &str, server: &str) -> Option<String> {
        let prefix = format!("mcp/{}/", server);
        tool_name.strip_prefix(&prefix).map(|s| s.to_string())
    }
}

