use crate::error::AvixError;

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct VfsPath(String);

impl VfsPath {
    pub fn parse(s: &str) -> Result<Self, AvixError> {
        if !s.starts_with('/') {
            return Err(AvixError::ConfigParse(format!(
                "VFS path must be absolute: '{s}'"
            )));
        }
        if s.contains("..") {
            return Err(AvixError::ConfigParse(format!(
                "VFS path must not contain '..': '{s}'"
            )));
        }
        Ok(Self(s.to_string()))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }

    pub fn parent(&self) -> Option<VfsPath> {
        let (s, _) = self.0.rsplit_once('/')?;
        if s.is_empty() {
            Some(VfsPath("/".to_string()))
        } else {
            Some(VfsPath(s.to_string()))
        }
    }

    pub fn file_name(&self) -> Option<&str> {
        self.0.rsplit_once('/').map(|(_, name)| name)
    }
}

use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::RwLock;

use super::path::VfsPath;
use crate::error::AvixError;

#[derive(Debug, Default)]
pub struct MemFs {
    files: Arc<RwLock<HashMap<String, Vec<u8>>>>,
}

impl MemFs {
    pub fn new() -> Self {
        Self::default()
    }

    pub async fn write(&self, path: &VfsPath, content: Vec<u8>) -> Result<(), AvixError> {
        self.files
            .write()
            .await
            .insert(path.as_str().to_string(), content);
        Ok(())
    }

    pub async fn read(&self, path: &VfsPath) -> Result<Vec<u8>, AvixError> {
        self.files
            .read()
            .await
            .get(path.as_str())
            .cloned()
            .ok_or_else(|| AvixError::ConfigParse(format!("ENOENT: {}", path.as_str())))
    }

    pub async fn delete(&self, path: &VfsPath) -> Result<(), AvixError> {
        self.files
            .write()
            .await
            .remove(path.as_str())
            .ok_or_else(|| AvixError::ConfigParse(format!("ENOENT: {}", path.as_str())))?;
        Ok(())
    }

    pub async fn exists(&self, path: &VfsPath) -> bool {
        self.files.read().await.contains_key(path.as_str())
    }

    pub async fn list(&self, dir: &VfsPath) -> Result<Vec<String>, AvixError> {
        let prefix = format!("{}/", dir.as_str().trim_end_matches('/'));
        let guard = self.files.read().await;
        let entries: Vec<String> = guard
            .keys()
            .filter(|k| k.starts_with(&prefix))
            .filter_map(|k| {
                let rest = &k[prefix.len()..];
                // Only immediate children (no '/' in the remainder)
                if rest.contains('/') {
                    None
                } else {
                    Some(rest.to_string())
                }
            })
            .collect();
        if entries.is_empty() {
            // Check if any file exists under this dir at all
            let any = guard.keys().any(|k| k.starts_with(&prefix));
            if !any {
                return Err(AvixError::ConfigParse(format!("ENOENT: {}", dir.as_str())));
            }
        }
        Ok(entries)
    }
}

use std::sync::atomic::{AtomicBool, Ordering};

use tokio::sync::{mpsc, Mutex};
use uuid::Uuid;

#[derive(Debug, thiserror::Error)]
pub enum PipeError {
    #[error("SIGPIPE: pipe {0} is closed")]
    Closed(String),
    #[error("pipe {0} is full (backpressure)")]
    Full(String),
}

pub struct Pipe {
    pub id: String,
    pub owner_pid: u32,
    tx: mpsc::Sender<String>,
    rx: Mutex<mpsc::Receiver<String>>,
    closed: AtomicBool,
}

impl Pipe {
    pub fn new(owner_pid: u32, capacity: usize) -> Self {
        let (tx, rx) = mpsc::channel(capacity);
        Self {
            id: Uuid::new_v4().to_string(),
            owner_pid,
            tx,
            rx: Mutex::new(rx),
            closed: AtomicBool::new(false),
        }
    }

    pub async fn write(&self, msg: String) -> Result<(), PipeError> {
        if self.closed.load(Ordering::SeqCst) {
            return Err(PipeError::Closed(self.id.clone()));
        }
        self.tx.try_send(msg).map_err(|e| match e {
            mpsc::error::TrySendError::Closed(_) => PipeError::Closed(self.id.clone()),
            mpsc::error::TrySendError::Full(_) => PipeError::Full(self.id.clone()),
        })
    }

    pub async fn read(&self) -> Option<String> {
        let mut rx = self.rx.lock().await;
        rx.recv().await
    }

    pub fn close(&self) {
        self.closed.store(true, Ordering::SeqCst);
    }

    pub fn is_closed(&self) -> bool {
        self.closed.load(Ordering::SeqCst)
    }
}

