        Self::default()
    }

    pub async fn register(&self, name: &str, endpoint: &str) {
        self.services
            .write()
            .await
            .insert(name.to_string(), endpoint.to_string());
    }

    pub async fn deregister(&self, name: &str) {
        self.services.write().await.remove(name);
    }

    pub async fn lookup(&self, name: &str) -> Option<String> {
        self.services.read().await.get(name).cloned()
    }

    pub async fn register_tool(&self, tool: &str, service: &str) {
        self.tools
            .write()
            .await
            .insert(tool.to_string(), service.to_string());
    }

    pub async fn service_for_tool(&self, tool: &str) -> Option<String> {
        self.tools.read().await.get(tool).cloned()
    }

    pub async fn tool_count(&self) -> usize {
        self.tools.read().await.len()
    }
}

use std::collections::HashMap;

use super::store::{SecretsError, SecretsStore};

/// Inject secrets for an agent into an environment map
pub fn inject_secrets(
    store: &SecretsStore,
    namespace: &str,
    env: &mut HashMap<String, String>,
) -> Result<(), SecretsError> {
    let keys = store.list(namespace);
    for key in keys {
        let plaintext = store.get(namespace, &key)?;
        let value = String::from_utf8_lossy(&plaintext).into_owned();
        let env_name = format!("AVIX_SECRET_{}", key.to_uppercase().replace('-', "_"));
        env.insert(env_name, value);
    }
    Ok(())
}

