use redb::{Database, TableDefinition};
use std::path::PathBuf;

const TABLE: TableDefinition<&str, &str> = TableDefinition::new("sessions");

pub struct SessionStore {
    db: Database,
}

impl SessionStore {
    pub async fn open(path: PathBuf) -> Result<Self, AvixError> {
        let db = Database::create(&path).map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        // Ensure table exists
        let write_txn = db
            .begin_write()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        {
            write_txn
                .open_table(TABLE)
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        }
        write_txn
            .commit()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        Ok(Self { db })
    }

    pub async fn save(&self, entry: &SessionEntry) -> Result<(), AvixError> {
        let json =
            serde_json::to_string(entry).map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        let write_txn = self
            .db
            .begin_write()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        {
            let mut table = write_txn
                .open_table(TABLE)
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
            table
                .insert(entry.session_id.as_str(), json.as_str())
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        }
        write_txn
            .commit()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        Ok(())
    }

    pub async fn load(&self, session_id: &str) -> Result<Option<SessionEntry>, AvixError> {
        let read_txn = self
            .db
            .begin_read()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        let table = read_txn
            .open_table(TABLE)
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        match table
            .get(session_id)
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?
        {
            Some(v) => {
                let entry = serde_json::from_str(v.value())
                    .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
                Ok(Some(entry))
            }
            None => Ok(None),
        }
    }

    pub async fn delete(&self, session_id: &str) -> Result<(), AvixError> {
        let write_txn = self
            .db
            .begin_write()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        {
            let mut table = write_txn
                .open_table(TABLE)
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
            table
                .remove(session_id)
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        }
        write_txn
            .commit()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        Ok(())
    }

    pub async fn list_all(&self) -> Result<Vec<SessionEntry>, AvixError> {
        let read_txn = self
            .db
            .begin_read()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        let table = read_txn
            .open_table(TABLE)
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        use redb::ReadableTable;
        let mut entries = Vec::new();
        let iter = table
            .iter()
            .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
        for item in iter {
            let (_, v) = item.map_err(|e| AvixError::ConfigParse(e.to_string()))?;
            let entry: SessionEntry = serde_json::from_str(v.value())
                .map_err(|e| AvixError::ConfigParse(e.to_string()))?;
            entries.push(entry);
        }
        Ok(entries)
    }
}

use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::{broadcast, RwLock};

use super::kind::{Signal, SignalKind};
use crate::types::Pid;

const CHANNEL_CAPACITY: usize = 64;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct SubscriptionId(u64);

pub struct Subscription {
    pub(crate) id: SubscriptionId,
    inner: broadcast::Receiver<Signal>,
}

impl Subscription {
    pub fn id(&self) -> SubscriptionId {
        self.id
    }

    pub async fn recv(&mut self) -> Option<Signal> {
        self.inner.recv().await.ok()
    }
}

struct PidEntry {
    sender: broadcast::Sender<Signal>,
    sub_count: usize,
}

#[derive(Default)]
pub struct SignalBus {
    table: Arc<RwLock<HashMap<u32, PidEntry>>>,
    next_id: Arc<std::sync::atomic::AtomicU64>,
}

impl SignalBus {
    pub fn new() -> Self {
        Self::default()
    }

    pub async fn subscribe(&self, pid: Pid) -> Subscription {
        let id = SubscriptionId(
            self.next_id
                .fetch_add(1, std::sync::atomic::Ordering::Relaxed),
        );
        let mut table = self.table.write().await;
        let entry = table.entry(pid.as_u32()).or_insert_with(|| PidEntry {
            sender: broadcast::channel(CHANNEL_CAPACITY).0,
            sub_count: 0,
        });
        entry.sub_count += 1;
        let rx = entry.sender.subscribe();
        Subscription { id, inner: rx }
    }

    pub async fn unsubscribe(&self, pid: Pid, _id: SubscriptionId) {
        let mut table = self.table.write().await;
        if let Some(entry) = table.get_mut(&pid.as_u32()) {
            entry.sub_count = entry.sub_count.saturating_sub(1);
            if entry.sub_count == 0 {
                table.remove(&pid.as_u32());
            }
        }
    }

    pub async fn send(&self, signal: Signal) -> Result<(), ()> {
        let table = self.table.read().await;
        if let Some(entry) = table.get(&signal.target.as_u32()) {
            let _ = entry.sender.send(signal);
        }
        Ok(())
    }

    pub async fn broadcast(&self, kind: SignalKind, payload: serde_json::Value) {
        let table = self.table.read().await;
        for (pid_u32, entry) in table.iter() {
            let sig = Signal {
                target: crate::types::Pid::new(*pid_u32),
                kind: kind.clone(),
                payload: payload.clone(),
            };
            let _ = entry.sender.send(sig);
        }
    }

    pub async fn subscriber_count(&self, pid: Pid) -> usize {
        self.table
            .read()
            .await
            .get(&pid.as_u32())
            .map(|e| e.sub_count)
            .unwrap_or(0)
    }
}

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
