        match self {
            Self::Start => "SIGSTART",
            Self::Pause => "SIGPAUSE",
            Self::Resume => "SIGRESUME",
            Self::Kill => "SIGKILL",
            Self::Stop => "SIGSTOP",
            Self::Save => "SIGSAVE",
            Self::Pipe => "SIGPIPE",
            Self::Escalate => "SIGESCALATE",
        }
    }
}

