impl Role {
    pub fn can_access_domain(&self, domain: &str) -> bool {
        match domain {
            "proc" | "fs" | "llm" | "exec" | "jobs" => true,
            "sys" | "cap" => *self >= Role::Admin,
            "kernel" => *self >= Role::Operator,
            _ => false,
        }
    }
}

